option.value:
# Example Lovelace Dashboard Card for Smart Plant Watering
# Add this to your Home Assistant dashboard

type: vertical-stack
cards:
  # Current Status Card
  - type: markdown
    content: |
      ##  Smart Watering Status

      **Current Status:** {{ states('input_text.smart_watering_status') | default('Not configured', true) }}

      **Consecutive Dry Days:** {{ states('input_number.smart_watering_dry_days') | int(0) }}

      {% set history = states('input_text.smart_watering_history') %}
      {% if history and history != 'unknown' and history != '' %}
        {% set sessions = history.split(' | ') %}
        {% set last = sessions[0].split(': ')[1].split(', ') if sessions|length > 0 else [] %}
        {% if last|length >= 2 %}
      **Last Session:** {{ last[1] }} ({{ last[0] }})
        {% endif %}
      {% else %}
      **Last Session:** No data yet
      {% endif %}
    title: Current Status

  # History Card
  - type: markdown
    content: |
      ##  Water Usage per Session

      {% set history = states('input_text.smart_watering_history') %}
      {% if history and history != 'unknown' and history != '' %}
        {% for line in history.split(' | ') %}
          {% set parts = line.split(': ') %}
          {% if parts|length == 2 %}
            {% set date = parts[0] %}
            {% set details = parts[1].split(', ') %}
            {% if details|length >= 3 %}
      - **{{ date }}**: {{ details[1] }} - {{ details[0] }}, {{ details[2] }}
            {% else %}
      - {{ line }}
            {% endif %}
          {% endif %}
        {% endfor %}
      {% else %}
      *No watering sessions yet*
      {% endif %}

      ---
      **Total Cumulative:** {{ states('input_number.smart_watering_total_liters') | float(0) | round(1) }} L
    title: Session History

  # Weather & Conditions
  - type: entities
    title: Current Conditions
    entities:
      - entity: weather.irm_kmi_home
        name: Weather
      - entity: sensor.water_valve_water_consumed
        name: Total Water (SWV)
      - entity: switch.water_valve
        name: Valve Control

  # Chart: Water Usage Trend
  - type: history-graph
    title: Water Usage Trend (7 days)
    hours_to_show: 168
    entities:
      - entity: input_number.smart_watering_total_liters
        name: Cumulative Liters

# Helper Creation Guide
# Create these helpers in Settings > Devices & Services > Helpers:
#
# 1. input_text.smart_watering_status
#    - Name: "Smart Watering - Status"
#    - Max length: 255
#
# 2. input_text.smart_watering_history
#    - Name: "Smart Watering - History"
#    - Max length: 255
#
# 3. input_number.smart_watering_total_liters
#    - Name: "Smart Watering - Total Liters"
#    - Min: 0, Max: 99999, Step: 0.1
#
# 4. input_number.smart_watering_dry_days
#    - Name: "Smart Watering - Dry Days"
#    - Min: 0, Max: 30, Step: 1
